    atsKeywords: ['modelado de datos', 'modelado dimensional', 'esquema estrella', 'esquema copo de nieve', 'entidad-relación', 'diagrama ER', 'Data Vault', 'normalización', 'desnormalización', 'diseño de esquemas', 'modelo conceptual', 'modelo lógico'],
