    atsKeywords: ['gobernanza de datos', 'custodia de datos', 'catálogo de datos', 'gestión de metadatos', 'linaje de datos', 'privacidad de datos', 'GDPR', 'clasificación de datos', 'gestión de datos maestros', 'políticas de datos', 'cumplimiento', 'gestión de calidad de datos'],
