    atsKeywords: ['narración de datos', 'comunicación de datos', 'presentación de datos', 'comunicación de insights', 'reportes ejecutivos', 'narrativa de datos', 'comunicación con stakeholders', 'storytelling analítico', 'presentaciones basadas en datos'],
